        {
            var prefs = new NotificationPrefs(
                _emailNotifications,
                _pushNotifications,
                _weeklyDigest,
                new List<string>(_mutedChannels));
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _toastMessage = "Notification preferences saved!";
            _toastIsError = false;
        }
        catch (Exception ex)
        {
            _toastMessage = $"Failed to save: {ex.Message}";
            _toastIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

