                    <label for="confirmPwd">Confirm New Password</label>
                    <input id="confirmPwd" type="password" @bind="_confirmPassword" />
                </div>

                <button class="btn btn-primary" @onclick="ChangePasswordAsync"
                        disabled="@_changingPassword">
                    @(_changingPassword ? "Updating…" : "Update Password")
                </button>
