</div>

@if (_toastMessage is not null)
{
    <div class="toast-message @(_toastIsError ? "toast-error" : "toast-success")">
        @_toastMessage
    </div>
}

@if (_loading)
{
    <p>Loading notification preferences…</p>
}
else
{
    <div class="form-card">
        <div class="toggle-row">
            <div>
                <div class="toggle-label">Email Notifications</div>
                <div class="toggle-description">Receive updates via email</div>
            </div>
            <label class="toggle-switch">
                <input type="checkbox" @bind="_emailNotifications" />
                <span class="toggle-slider"></span>
            </label>
        </div>

        <div class="toggle-row">
            <div>
                <div class="toggle-label">Push Notifications</div>
                <div class="toggle-description">Receive push alerts on your devices</div>
            </div>
            <label class="toggle-switch">
                <input type="checkbox" @bind="_pushNotifications" />
                <span class="toggle-slider"></span>
            </label>
        </div>

        <div class="toggle-row">
            <div>
                <div class="toggle-label">Weekly Digest</div>
                <div class="toggle-description">Get a summary email every week</div>
            </div>
            <label class="toggle-switch">
                <input type="checkbox" @bind="_weeklyDigest" />
                <span class="toggle-slider"></span>
            </label>
        </div>
    </div>

    <div class="form-card" style="margin-top: 1rem;">
        <h4 style="margin:0 0 1rem; font-size:1rem; font-weight:600;">Muted Channels</h4>
        <div class="channel-list">
            @foreach (var channel in _allChannels)
            {
                var ch = channel;
                <label class="channel-item">
                    <input type="checkbox"
                           checked="@_mutedChannels.Contains(ch)"
                           @onchange="e => ToggleMute(ch, (bool)(e.Value ?? false))" />
                    <span class="channel-name">#@ch</span>
                    @if (_mutedChannels.Contains(ch))
                    {
                        <span class="channel-muted-badge">muted</span>
                    }
                </label>
            }
        </div>
    </div>

    <div class="btn-group">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Preferences")
        </button>
    </div>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;
    private bool _toastIsError;

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _mutedChannels = [];

    private static readonly List<string> _allChannels =
        MockSettingsService.GetAllChannels();

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = new List<string>(prefs.MutedChannels);
        _loading = false;
    }

    private void ToggleMute(string channel, bool isMuted)
    {
        if (isMuted && !_mutedChannels.Contains(channel))
            _mutedChannels.Add(channel);
        else if (!isMuted)
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _toastMessage = null;
        try
        {
            var prefs = new NotificationPrefs(
                _emailNotifications,
                _pushNotifications,
                _weeklyDigest,
                new List<string>(_mutedChannels));
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _toastMessage = "Notification preferences saved!";
            _toastIsError = false;
        }
        catch (Exception ex)
        {
            _toastMessage = $"Failed to save: {ex.Message}";
            _toastIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

