    private SecuritySettings? _settings;

    // Password change
    private bool _passwordExpanded;
    private bool _changingPassword;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";

    // Session revocation
    private ActiveSession? _sessionToRevoke;

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        _toastMessage = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            _toastMessage = "Please fill in all password fields.";
            _toastIsError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _toastMessage = "New password and confirmation do not match.";
            _toastIsError = true;
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _settings = await SettingsService.GetSecuritySettingsAsync();
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _toastMessage = "Password updated successfully!";
            _toastIsError = false;
        }
        catch (Exception ex)
        {
            _toastMessage = $"Failed to change password: {ex.Message}";
            _toastIsError = true;
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;

        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _settings = await SettingsService.GetSecuritySettingsAsync();
            _toastMessage = $"Session on {_sessionToRevoke.Device} revoked.";
            _toastIsError = false;
        }
        catch (Exception ex)
        {
            _toastMessage = $"Failed to revoke session: {ex.Message}";
            _toastIsError = true;
        }
        finally
        {
            _sessionToRevoke = null;
        }
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

@using sv_f1be586d93d54b45ba4b8b5dad765dbe.Services
@inject ISettingsService SettingsService

<div class="section-header">
    <h2>Appearance</h2>
    <p>Customize how the application looks and feels.</p>
</div>

@if (_toastMessage is not null)
{
    <div class="toast-message @(_toastIsError ? "toast-error" : "toast-success")">
        @_toastMessage
    </div>
}

@if (_loading)
{
    <p>Loading appearance settings…</p>
}
else
{
    <div class="form-card">
        <!-- Theme -->
        <div class="form-group">
            <label>Theme</label>
            <div class="radio-group">
                @foreach (var theme in _themes)
                {
                    var t = theme;
                    <div class="radio-option">
                        <input type="radio" name="theme" id="theme-@t" value="@t"
                               checked="@(_theme == t)"
                               @onchange="() => _theme = t" />
                        <label for="theme-@t">@t</label>
                    </div>
                }
            </div>
        </div>

        <!-- Font Size -->
        <div class="form-group">
            <label>Font Size</label>
            <div class="radio-group">
                @foreach (var size in _fontSizes)
                {
                    var s = size;
                    <div class="radio-option">
                        <input type="radio" name="fontSize" id="font-@s" value="@s"
                               checked="@(_fontSize == s)"
                               @onchange="() => _fontSize = s" />
                        <label for="font-@s">@s</label>
                    </div>
                }
            </div>
        </div>

        <!-- Language -->
        <div class="form-group">
            <label for="language">Language</label>
            <select id="language" @bind="_language">
                @foreach (var lang in _languages)
                {
                    <option value="@lang">@lang</option>
                }
            </select>
        </div>

        <!-- Compact Mode -->
        <div class="toggle-row" style="border-bottom:none;">
            <div>
                <div class="toggle-label">Compact Mode</div>
                <div class="toggle-description">Reduce spacing and padding throughout the UI</div>
            </div>
            <label class="toggle-switch">
                <input type="checkbox" @bind="_compactMode" />
                <span class="toggle-slider"></span>
            </label>
        </div>
    </div>

    <!-- Live Preview -->
    <div class="form-card" style="margin-top:1rem;">
        <div class="preview-label">Live Preview</div>
        <div class="live-preview" style="@GetPreviewStyle()">
            <h4 style="margin:0 0 0.5rem;">Preview Heading</h4>
            <p style="margin:0 0 0.5rem;">This is sample body text showing how your chosen settings will look. The theme, font size, and compact mode are reflected below.</p>
            <div style="display:flex; gap:0.5rem; flex-wrap:wrap; align-items:center;">
                <span style="@GetPreviewBadgeStyle()">Badge</span>
                <button style="@GetPreviewButtonStyle()">Sample Button</button>
            </div>
            <div style="margin-top:0.5rem; font-size:0.8em; opacity:0.7;">
                Theme: @_theme · Font: @_fontSize · Language: @_language · Compact: @(_compactMode ? "On" : "Off")
            </div>
        </div>
    </div>

    <div class="btn-group">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving…" : "Save")
        </button>
    </div>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;
    private bool _toastIsError;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _toastMessage = null;
        try
        {
            await SettingsService.SaveAppearanceAsync(
                new AppearanceSettings(_theme, _fontSize, _language, _compactMode));
            _toastMessage = "Appearance settings saved!";
            _toastIsError = false;
        }
        catch (Exception ex)
        {
            _toastMessage = $"Failed to save: {ex.Message}";
            _toastIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private string GetPreviewStyle()
    {
        var bg = _theme switch
        {
            "Dark" => "background:#1e1e2e; color:#cdd6f4;",
            "System" => "background:#f0f0f0; color:#333; border-left:3px solid #0d6efd;",
            _ => "background:#fff; color:#212529;"
        };

        var fs = _fontSize switch
        {
            "Small" => "font-size:0.8rem;",
            "Large" => "font-size:1.15rem;",
            _ => "font-size:0.95rem;"
        };

        var padding = _compactMode ? "padding:0.6rem;" : "padding:1.25rem;";

        return $"{bg} {fs} {padding}";
    }

    private string GetPreviewBadgeStyle()
    {
        var bg = _theme == "Dark"
            ? "background:#89b4fa; color:#1e1e2e;"
            : "background:#cfe2ff; color:#084298;";
        var padding = _compactMode ? "padding:0.1rem 0.4rem;" : "padding:0.25rem 0.65rem;";
        return $"{bg} {padding} border-radius:20px; font-size:0.8em; font-weight:500;";
    }

    private string GetPreviewButtonStyle()
    {
        var bg = _theme == "Dark"
            ? "background:#89b4fa; color:#1e1e2e; border:none;"
            : "background:#0d6efd; color:#fff; border:none;";
        var padding = _compactMode ? "padding:0.25rem 0.6rem;" : "padding:0.4rem 1rem;";
        return $"{bg} {padding} border-radius:6px; font-size:0.85em; cursor:pointer;";
    }
}

