{"file_text": "@using sv_f1be586d93d54b45ba4b8b5dad765dbe.Services
@inject ISettingsService SettingsService

<div class="section-header">
    <h2>Security</h2>
    <p>Manage your password, two-factor authentication, and active sessions.</p>
</div>

@if (_toastMessage is not null)
{
    <div class="toast-message @(_toastIsError ? "toast-error" : "toast-success")">
        @_toastMessage
    </div>
}

@if (_loading)
{
    <p>Loading security settings…</p>
}
else
{
    <!-- Change Password -->
    <div class="expandable-panel">
        <button class="expandable-header" @onclick="() => _passwordExpanded = !_passwordExpanded">
            <span>Change Password</span>
            <span class="expand-icon @(_passwordExpanded ? "expanded" : "")">▶</span>
        </button>
        @if (_passwordExpanded)
        {
            <div class="expandable-body">
                @if (_settings!.LastPasswordChange.HasValue)
                {
                    <p style="color:#6c757d; font-size:0.85rem; margin-bottom:1rem;">
                        Last changed: @_settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                    </p>
                }

                <div class="form-group">
                    <label for="currentPwd">Current Password</label>
                    <input id="currentPwd" type="password" @bind="_currentPassword" />
                </div>
                <div class="form-group">
                    <label for="newPwd">New Password</label>
                    <input id="newPwd" type="password" @bind="_newPassword" />
                </div>
                <div class="form-group">
                    <label for="confirmPwd">Confirm New Password</label>
                    <input id="confirmPwd" type="password" @bind="_confirmPassword" />
                </div>

                <button class="btn btn-primary" @onclick="ChangePasswordAsync"
                        disabled="@_changingPassword">
                    @(_changingPassword ? "Updating…" : "Update Password")
                </button>
            </div>
        }
    </div>

    <!-- Two-Factor Authentication -->
    <div class="form-card">
        <div class="toggle-row">
            <div>
                <div class="toggle-label">Two-Factor Authentication</div>
                <div style="margin-top:0.25rem;">
                    @if (_settings!.TwoFactorEnabled)
                    {
                        <span class="status-badge status-enabled">✓ Enabled</span>
                    }
                    else
                    {
                        <span class="status-badge status-disabled">✗ Disabled</span>
                    }
                </div>
            </div>
            <label class="toggle-switch">
                <input type="checkbox" checked="@_settings.TwoFactorEnabled" disabled />
                <span class="toggle-slider"></span>
            </label>
        </div>
    </div>

    <!-- Active Sessions -->
    <div class="form-card" style="margin-top: 1rem;">
        <h4 style="margin:0 0 1rem; font-size:1rem; font-weight:600;">Active Sessions</h4>
        @if (_settings!.Sessions.Count == 0)
        {
            <p style="color:#6c757d;">No active sessions.</p>
        }
        else
        {
            <table class="data-table">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in _settings.Sessions)
                    {
                        var isCurrentSession = session.Id == _settings.Sessions[0].Id;
                        <tr>
                            <td>
                                @session.Device
                                @if (isCurrentSession)
                                {
                                    <span class="current-session-badge">current</span>
                                }
                            </td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (!isCurrentSession)
                                {
                                    <button class="btn btn-danger"
                                            style="padding:0.3rem 0.75rem; font-size:0.8rem;"
                                            @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        }
    </div>
}

@if (_sessionToRevoke is not null)
{
    <div class="dialog-overlay" @onclick="CancelRevoke">
        <div class="dialog-box" @onclick:stopPropagation="true">
            <h4>Revoke Session</h4>
            <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from @_sessionToRevoke.Location?</p>
            <div class="btn-group" style="margin-top:0;">
                <button class="btn btn-danger" @onclick="ConfirmRevokeAsync">Revoke</button>
                <button class="btn btn-outline" @onclick="CancelRevoke">Cancel</button>
            </div>
        </div>
    </div>
}

@code {
    private bool _loading = true;
    private string? _toastMessage;
    private bool _toastIsError;
    private SecuritySettings? _settings;

    // Password change
    private bool _passwordExpanded;
    private bool _changingPassword;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";

    // Session revocation
    private ActiveSession? _sessionToRevoke;

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        _toastMessage = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            _toastMessage = "Please fill in all password fields.";
            _toastIsError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _toastMessage = "New password and confirmation do not match.";
            _toastIsError = true;
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _settings = await SettingsService.GetSecuritySettingsAsync();
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _toastMessage = "Password updated successfully!";
            _toastIsError = false;
        }
        catch (Exception ex)
        {
            _toastMessage = $"Failed to change password: {ex.Message}";
            _toastIsError = true;
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;

        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _settings = await SettingsService.GetSecuritySettingsAsync();
            _toastMessage = $"Session on {_sessionToRevoke.Device} revoked.";
            _toastIsError = false;
        }
        catch (Exception ex)
        {
            _toastMessage = $"Failed to revoke session: {ex.Message}";
            _toastIsError = true;
        }
        finally
        {
            _sessionToRevoke = null;
        }
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}
