toolArgs.file_text:
@page "/settings"
@using sv_f1be586d93d54b45ba4b8b5dad765dbe.Services
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <nav class="settings-sidebar" aria-label="Settings sections">
        <h3 class="sidebar-title">Settings</h3>
        <ul class="sidebar-nav">
            @foreach (var section in _sections)
            {
                <li>
                    <button class="sidebar-link @(section.Key == _activeSection ? "active" : "")"
                            @onclick="() => SetActiveSection(section.Key)">
                        <span class="sidebar-icon">@section.Icon</span>
                        @section.Label
                    </button>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "profile":
                <ProfileSection />
                break;
            case "notifications":
                <NotificationsSection />
                break;
            case "security":
                <SecuritySection />
                break;
            case "appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "profile";

    private readonly record struct SectionDef(string Key, string Label, string Icon);

    private static readonly SectionDef[] _sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨"),
    ];

    private void SetActiveSection(string key)
    {
        _activeSection = key;
    }
}

@using sv_f1be586d93d54b45ba4b8b5dad765dbe.Services
@inject ISettingsService SettingsService

<div class="section-header">
    <h2>Profile</h2>
    <p>Manage your personal information and public profile.</p>
</div>

@if (_toastMessage is not null)
{
    <div class="toast-message @(_toastIsError ? "toast-error" : "toast-success")">
        @_toastMessage
    </div>
}

@if (_loading)
{
    <p>Loading profile…</p>
}
else
{
    <div class="form-card">
        <div class="avatar-area">
            <img class="avatar-preview" src="@_avatarUrl" alt="Avatar preview" />
            <div>
                <div style="font-weight:500;">Avatar</div>
                <div class="avatar-url">@_avatarUrl</div>
            </div>
        </div>

        <div class="form-group">
            <label for="displayName">Display Name</label>
            <input id="displayName" type="text" @bind="_displayName" />
        </div>

        <div class="form-group">
            <label for="email">Email</label>
            <input id="email" type="email" @bind="_email" />
        </div>

        <div class="form-group">
            <label for="bio">Bio</label>
            <textarea id="bio" @bind="_bio"></textarea>
        </div>

        <div class="form-group">
            <label for="avatarUrl">Avatar URL</label>
            <input id="avatarUrl" type="text" @bind="_avatarUrl" />
        </div>

        <div class="btn-group">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Changes")
            </button>
            <button class="btn btn-outline" @onclick="DiscardChanges">
                Discard Changes
            </button>
        </div>
    </div>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;
    private bool _toastIsError;

    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";

    // Last-saved state for discard
    private UserProfile? _savedProfile;

    protected override async Task OnInitializedAsync()
    {
        var profile = await SettingsService.GetProfileAsync();
        _savedProfile = profile;
        ApplyProfile(profile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _bio = profile.Bio;
        _avatarUrl = profile.AvatarUrl;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _toastMessage = null;
        try
        {
            var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(profile);
            _savedProfile = profile;
            _toastMessage = "Profile saved successfully!";
            _toastIsError = false;
        }
        catch (Exception ex)
        {
            _toastMessage = $"Failed to save profile: {ex.Message}";
            _toastIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
            _toastMessage = null;
        }
    }
}

